# Flip Countdown

Mechanical flip-clock countdown using BigInt arithmetic for arbitrarily large numbers. Each digit is a FlipUnit with top/bottom card halves and a flipping overlay that animates via CSS keyframes. Supports counting up or down between any two values. Requires flip CSS keyframe definitions in global stylesheet.

## Use when
- Displaying a countdown timer on a launch or event page.
- Adding a live countdown to an event landing page.
- Showing an animated numerical timer with a satisfying mechanical flip aesthetic.

## Stack
- Framework: react
- Libraries: none
- Requires: tailwind

## Install
```bash
none
```

## Component — flip-countdown.tsx
```tsx
import React, { useState, useEffect, useMemo } from 'react';

const cn = (...inputs: (string | undefined | null | boolean)[]) =>
  inputs.filter(Boolean).join(' ');

const FlipUnit = ({
  digit,
  cardStyle,
}: {
  digit: string;
  cardStyle: React.CSSProperties;
}) => {
  const [currentDigit, setCurrentDigit] = useState(digit);
  const [previousDigit, setPreviousDigit] = useState(digit);
  const [isFlipping, setIsFlipping] = useState(false);

  useEffect(() => {
    if (digit !== currentDigit) {
      setPreviousDigit(currentDigit);
      setCurrentDigit(digit);
      setIsFlipping(true);
    }
  }, [digit, currentDigit]);

  const handleAnimationEnd = () => {
    setIsFlipping(false);
    setPreviousDigit(digit);
  };

  return (
    <div className="flip-unit" style={cardStyle}>
      <div className="flip-card flip-card__bottom">{currentDigit}</div>
      <div className="flip-card flip-card__top">{previousDigit}</div>
      <div
        className={cn('flipper', isFlipping && 'is-flipping')}
        onAnimationEnd={handleAnimationEnd}
      >
        <div className="flip-card flipper__top">{previousDigit}</div>
        <div className="flip-card flipper__bottom">{currentDigit}</div>
      </div>
    </div>
  );
};

export const FlipCountdown = ({
  countFrom = 99,
  countTo = 0,
  className,
  cardBgColor,
  textColor,
}: {
  countFrom?: number | string | bigint;
  countTo?: number | string | bigint;
  className?: string;
  cardBgColor?: string;
  textColor?: string;
}) => {
  const from = useMemo(() => BigInt(countFrom), [countFrom]);
  const to = useMemo(() => BigInt(countTo), [countTo]);
  const isCountingDown = from > to;
  const [count, setCount] = useState(from);

  useEffect(() => {
    if ((isCountingDown && count <= to) || (!isCountingDown && count >= to)) return;
    const timer = setInterval(() => {
      setCount((prevCount) => (isCountingDown ? prevCount - 1n : prevCount + 1n));
    }, 1000);
    return () => clearInterval(timer);
  }, [count, to, isCountingDown]);

  const paddedCount = useMemo(() => {
    const maxVal = from > to ? from : to;
    const numDigits = String(maxVal).length;
    const displayCount = count < 0n ? 0n : count;
    return String(displayCount).padStart(numDigits, '0');
  }, [count, from, to]);

  const cardStyle: React.CSSProperties = {
    '--flip-card-bg': cardBgColor,
    '--flip-card-text': textColor,
  } as React.CSSProperties;

  return (
    <div className={cn('flip-countdown-container', className)}>
      {paddedCount.split('').map((digit, index) => (
        <FlipUnit key={index} digit={digit} cardStyle={cardStyle} />
      ))}
    </div>
  );
};
```

## Demo
```tsx
import React, { useState } from 'react';
import { FlipCountdown } from "@/components/ui/flip-countdown";

export default function FlipCountdownDemo() {
  const [key, setKey] = useState(0);
  const [countFrom, setCountFrom] = useState('100');
  const [countTo, setCountTo] = useState('0');

  return (
    <div className="flex flex-col items-center gap-8 p-4">
      <FlipCountdown key={key} countFrom={countFrom} countTo={countTo} />
      {/* From/To inputs and Restart button */}
    </div>
  );
}
```

## Notes
- Requires CSS class definitions for `.flip-countdown-container`, `.flip-unit`, `.flip-card`, `.flip-card__top`, `.flip-card__bottom`, `.flipper`, `.flipper__top`, `.flipper__bottom`, `.is-flipping`.
- Requires these `@keyframes` added to your global CSS (e.g., `index.css` or `globals.css`):
  ```css
  @keyframes flip-top { 100% { transform: rotateX(-180deg); } }
  @keyframes flip-bottom { 100% { transform: rotateX(0deg); } }
  ```
- Uses `BigInt` arithmetic (`1n`) for safe handling of large numbers — requires ES2020+ target in TypeScript config.
